function sImg = fImgSmoothV01(img)%% smooth image with pyramidal filter (5by5)% sImg = fImgSmoothV01(img)% img: input image% sImg: smoothed image%% image smoothing, ver.1%% Written by Kei Nakamura% Created on Friday, May 29th 2009.% Modified on%% main body[iRow,iClm] = size(img);    % input row and columncRow = iRow-4; cClm = iClm-4;   % core row and columncImg = zeros(cRow,cClm);    % core imagesubImg = zeros(5,5);        % sub imagepyr = [1 2 3 2 1;2 4 6 4 2;3 6 9 6 3;2 4 6 4 2;1 2 3 2 1]/81;  %pyramid filterfor ii=1:cRow    for jj=1:cClm        subImg(:,:) = img(ii:ii+4,jj:jj+4);     % take sub image        cImg(ii,jj) = sum(sum(subImg.*pyr));    % calculate average    endend        sImg = img;sImg(3:end-2,3:end-2) = cImg;   % replace middle part
